try {
  sim.defineChapters(['ALPHA', 'BETA', 'GAMMA'])
  const wd = sim.worldData
  // a click (rising edge) completes the chapter → unlocks + steps into the next
  if (sim.edge('click', !!wd.mouse_down) && sim.act < sim.chapterCount()) sim.completeChapter()
  wd.gpuUniforms = [sim.act, 0, 0, 0]
  wd.hud = [{ id: 'ch', type: 'text', x: '14px', y: '12px',
    text: 'CHAPTER ' + sim.act + ' / ' + sim.chapterCount() + ' — ' + sim.chapterName() + '   (click to advance)',
    color: '#e0c070', fontSize: '14px' }]
} catch (e) {}

