fn visual_chdemo(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let act = uni(0);
  var col = vec3f(0.05, 0.06, 0.10);
  if (act > 0.5 && act < 1.5) { col = vec3f(0.22, 0.10, 0.32); }
  if (act > 1.5 && act < 2.5) { col = vec3f(0.08, 0.26, 0.30); }
  if (act > 2.5)              { col = vec3f(0.32, 0.22, 0.07); }
  // one lit bar per completed/entered chapter
  let bx = (uv.x * 0.5 + 0.5) * 6.0;
  let bar = floor(bx);
  if (bar < act && abs(uv.y) < 0.28 && fract(bx) < 0.72) { col += vec3f(1.0, 0.9, 0.55) * 0.9; }
  col *= 1.0 - 0.35 * pow(length(uv), 3.0);
  return vec4f(col, 1.0);
}
